import { useEffect } from 'react';
import * as turf from '@turf/turf';

const VehicleTracker = ({ vehicles, incidents }) => {
  useEffect(() => {
    const checkVehiclePositions = () => {
      vehicles.forEach(vehicle => {
        incidents.forEach(incident => {
          const vehiclePoint = turf.point([vehicle.longitude, vehicle.latitude]);
          const incidentCircle = turf.circle([incident.location_long, incident.location_lat], incident.radius, { units: 'miles' });

          const isInside = turf.booleanPointInPolygon(vehiclePoint, incidentCircle);

          if (isInside && !vehicle.insideIncidents?.includes(incident.incident_id)) {
            // Vehicle entered the incident circle
            console.log('Vehicle entered circle');
            vehicle.insideIncidents = [...(vehicle.insideIncidents || []), incident.incident_id];
            sendVehicleDataToServer(vehicle, incident, 'entered');
          } else if (!isInside && vehicle.insideIncidents?.includes(incident.incident_id)) {
            // Vehicle exited the incident circle
            console.log('Vehicle exited circle');
            vehicle.insideIncidents = vehicle.insideIncidents.filter(id => id !== incident.incident_id);
            sendVehicleDataToServer(vehicle, incident, 'exited');
          }
        });
      });
    };

    const intervalId = setInterval(checkVehiclePositions, 1000); // Check every second

    return () => clearInterval(intervalId); // Cleanup on component unmount
  }, [vehicles, incidents]);

  const sendVehicleDataToServer = async (vehicle, incident, status) => {
    try {
      const response = await fetch('http://localhost:3000/vehicle', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          latitude: vehicle.latitude,
          longitude: vehicle.longitude,
          displayName: vehicle.displayName,
          officer_name: vehicle.officer_name, // Add officer_name if available
          assignment: vehicle.assignment // Add assignment if available
        })
      });
      if (!response.ok) {
        throw new Error('Failed to send vehicle data to server');
      }
    } catch (error) {
      console.error('Error sending vehicle data to server:', error);
    }
  };

  return null; // No UI to render
};

export default VehicleTracker;
