import L from 'leaflet';
import policeCarIcon from '../images/icons/policecar.png';
import helicopterIcon from '../images/icons/helicopter.png';
import esuIcon from '../images/icons/esu.png';
import marineIcon from '../images/icons/marine.png';
import k9Icon from '../images/icons/k9.png';

export const formatDate = (dateString) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    const month = (date.getMonth() + 1).toString().padStart(2, '0');
    const day = date.getDate().toString().padStart(2, '0');
    const year = date.getFullYear();
    return `${month}-${day}-${year}`;
};
export const icons = {
    policeCar: createIcon(policeCarIcon),
    helicopter: createIcon(helicopterIcon),
    esu: createIcon(esuIcon),
    marine: createIcon(marineIcon),
    k9: createIcon(k9Icon)
};

function createIcon(url) {
    return L.divIcon({
        html: `<div class="rotated-icon"><img src="${url}" style="width: 38px; height: 38px;"></div>`,
        iconSize: [38, 38],
        iconAnchor: [19, 38],
        tooltipAnchor: [0, -20],
        className: ''
    });
}