// LayerControlModal.js
import React, { useState, useEffect } from 'react';
import { Modal, Button, Form } from 'react-bootstrap';

const LayerControlModal = ({ show, handleClose, csvFiles, selectedLayers, setSelectedLayers }) => {
  const handleCheckboxChange = (filename) => {
    if (selectedLayers.includes(filename)) {
      setSelectedLayers(selectedLayers.filter(layer => layer !== filename));
    } else {
      setSelectedLayers([...selectedLayers, filename]);
    }
  };

  return (
    <Modal show={show} onHide={handleClose} centered>
      <Modal.Header closeButton>
        <Modal.Title>Select Layers</Modal.Title>
      </Modal.Header>
      <Modal.Body>
        <Form>
          {csvFiles.map((file, index) => (
            <Form.Group key={index} controlId={`formCheckbox-${index}`}>
              <Form.Check 
                type="checkbox" 
                label={file}
                checked={selectedLayers.includes(file)}
                onChange={() => handleCheckboxChange(file)}
              />
            </Form.Group>
          ))}
        </Form>
      </Modal.Body>
      <Modal.Footer>
        <Button variant="secondary" onClick={handleClose}>
          Close
        </Button>
      </Modal.Footer>
    </Modal>
  );
};

export default LayerControlModal;
