import React, { useEffect, useRef, useState } from 'react'; // Add useState here
import { useMap } from 'react-leaflet';
import L from 'leaflet';
import { icons } from './utils'; // Adjust the path as needed

const fetchGeoJSONData = async () => {
    try {
        const response = await fetch('http://localhost:5000/locations'); // Fetch from Flask endpoint
        if (!response.ok) {
            throw new Error('Failed to fetch GeoJSON data');
        }
        return await response.json();
    } catch (error) {
        console.error('Error fetching GeoJSON data:', error);
        return null;
    }
};

const determineIconType = (displayName) => {
    if (displayName.includes('Aviation')) {
        return 'helicopter';
    } else if (displayName.includes('K9')) {
        return 'k9';
    } else if (displayName.includes('ESU')) {
        return 'esu';
    } else if (displayName.includes('Marine')) {
        return 'marine';
    } else {
        return 'policeCar';
    }
};

const VehicleLayer = ({ setVehicles }) => {
    const markersRef = useRef({});
    const map = useMap();
    const [vehicles, setVehicleState] = useState([]); // Add useState here

    useEffect(() => {
        const updateVehicleData = async () => {
            const data = await fetchGeoJSONData();
            if (data) {
                const vehicles = data.features.map((feature) => {
                    const { geometry, properties } = feature;
                    const { coordinates } = geometry;
                    const { displayName, heading } = properties;
                    const latitude = coordinates[1];
                    const longitude = coordinates[0];
                    const iconType = determineIconType(displayName);
                    return { displayName, latitude, longitude, heading, iconType };
                });
                setVehicleState(vehicles);
                setVehicles(vehicles); // Update parent component's state
            }
        };

        updateVehicleData();
        const intervalId = setInterval(updateVehicleData, 1000);

        return () => clearInterval(intervalId);
    }, [setVehicles]);

    useEffect(() => {
        if (!map) return;

        vehicles.forEach((vehicle) => {
            const { displayName, latitude, longitude, heading, iconType } = vehicle;
            const latlng = [latitude, longitude];
            const icon = icons[iconType];

            if (markersRef.current[displayName]) {
                const marker = markersRef.current[displayName];
                marker.setLatLng(latlng);
                const iconElement = marker.getElement().querySelector('img');
                if (iconElement) {
                    iconElement.style.transform = `rotate(${heading}deg)`;
                }
            } else {
                const marker = L.marker(latlng, { icon }).addTo(map);
                marker.bindTooltip(displayName, { permanent: true, direction: "top", className: 'custom-tooltip' });
                markersRef.current[displayName] = marker;

                const iconElement = marker.getElement().querySelector('img');
                if (iconElement) {
                    iconElement.style.transform = `rotate(${heading}deg)`;
                }
            }
        });
    }, [vehicles, map]);

    return null;
};

export default VehicleLayer;
