// CloseIncidentModal.js
import React, { useState, useEffect } from 'react';
import { Modal, Button, Form } from 'react-bootstrap';


const CloseIncidentModal = ({ show, onClose, onSubmit, incidentId }) => {
    const [dispositions, setDispositions] = useState([]);
    const [selectedDisposition, setSelectedDisposition] = useState('');
    const [notes, setNotes] = useState('');
    const [emailRequested, setEmailRequested] = useState(false);
    const [emailAddress, setEmailAddress] = useState('');

    useEffect(() => {
        // Fetch dispositions from the database
        fetch('http://localhost:3000/api/dispositions')
            .then(response => response.json())
            .then(data => setDispositions(data))
            .catch(error => console.error('Error fetching dispositions:', error));
    }, []);

    const handleSubmit = (event) => {
        event.preventDefault();
        const closeData = {
            incident_id: incidentId,
            disposition: selectedDisposition,
            notes: notes,
            email_requested: emailRequested,
            email_address: emailAddress
        };
        onSubmit(closeData);
        onClose();
    };

    return (
        <Modal show={show} onHide={onClose} centered>
            <Modal.Header closeButton>
                <Modal.Title>Close Incident</Modal.Title>
            </Modal.Header>
            <Modal.Body>
                <Form onSubmit={handleSubmit}>
                    <Form.Group controlId="formDisposition">
                        <Form.Label>Disposition</Form.Label>
                        <Form.Control
                            as="select"
                            value={selectedDisposition}
                            onChange={(e) => setSelectedDisposition(e.target.value)}
                            required
                        >
                            <option value="">Select Disposition</option>
                            {dispositions.map((disposition) => (
                                <option key={disposition.id} value={disposition.disposition_text}>
                                    {disposition.disposition_text}
                                </option>
                            ))}
                        </Form.Control>
                    </Form.Group>
                    <Form.Group controlId="formNotes" className="mt-3">
                        <Form.Label>Notes</Form.Label>
                        <Form.Control
                            as="textarea"
                            rows={3}
                            value={notes}
                            onChange={(e) => setNotes(e.target.value)}
                        />
                    </Form.Group>
                    <Form.Group controlId="formEmailRequested" className="mt-3">
                        <Form.Check
                            type="checkbox"
                            label="Would you like the log emailed to you?"
                            checked={emailRequested}
                            onChange={(e) => setEmailRequested(e.target.checked)}
                        />
                    </Form.Group>
                    <Form.Group controlId="formEmailAddress" className="mt-3">
                        <Form.Label>Email Address</Form.Label>
                        <Form.Control
                            type="email"
                            value={emailAddress}
                            onChange={(e) => setEmailAddress(e.target.value)}
                            required={emailRequested}
                        />
                    </Form.Group>
                    <Button variant="primary" type="submit" className="mt-3">
                        Submit
                    </Button>
                    <Button variant="secondary" onClick={onClose} className="mt-3 ms-2">
                        Close
                    </Button>
                </Form>
            </Modal.Body>
        </Modal>
    );
};

export default CloseIncidentModal;
