// IncidentModal.js
import React, { useState } from 'react';
import PropTypes from 'prop-types';
import { formatDate } from './utils';
import EditIncModal from './EditIncModal';

function IncidentModal({ incident, isActive, onClick }) {
    const [isEditModalOpen, setEditModalOpen] = useState(false);

    const handleDoubleClick = () => {
        console.log('Opening Edit Modal for Incident ID:', incident.incident_id); // Add this log
        setEditModalOpen(true);
    };

    return (
        <div 
            className={`incident-modal ${isActive ? 'active' : ''}`} 
            onClick={() => onClick(incident)}
            onDoubleClick={handleDoubleClick}  // Add double-click event
            style={{ 
                backgroundColor: isActive ? '#0567f7' : '#333',
                cursor: 'pointer'
            }}
        >
            <div className="incident-modal-header">
                <strong>{incident.name}</strong>
            </div>
            <div className="incident-modal-body">
                <p>Type: {incident.type_incident}</p>
                <p>Location: {incident.location_lat.toFixed(3)}, {incident.location_long.toFixed(3)}</p>
                <p>Date: {formatDate(incident.date)}</p>
                <p>Time: {incident.time}</p>
                <p>Incident Commander: {incident.incident_commander}</p>
                <p>Staging Manager: {incident.staging_manager}</p>
                <p>Communications: {incident.communications}</p>
            </div>
            {isEditModalOpen && (
                <EditIncModal
                    incidentId={incident.incident_id}
                    onClose={() => setEditModalOpen(false)}
                />
            )}
        </div>
    );
}

IncidentModal.propTypes = {
    incident: PropTypes.shape({
        incident_id: PropTypes.number.isRequired, // Ensure incident_id is included and required
        name: PropTypes.string.isRequired,
        type_incident: PropTypes.string.isRequired,
        location_lat: PropTypes.number.isRequired,
        location_long: PropTypes.number.isRequired,
        date: PropTypes.string.isRequired,
        time: PropTypes.string.isRequired,
        incident_commander: PropTypes.string.isRequired,
        staging_manager: PropTypes.string.isRequired,
        communications: PropTypes.string.isRequired,
    }).isRequired,
    isActive: PropTypes.bool.isRequired,
    onClick: PropTypes.func.isRequired,
};

export default IncidentModal;
